CREATE TEMP TABLE _ivan_leandro_completo_expected (
  slug text NOT NULL PRIMARY KEY,
  expected_rows int NOT NULL,
  expected_lme_rows int NOT NULL,
  old_coverage_id text NOT NULL,
  coverage_id text NOT NULL,
  coverage_scope text NOT NULL
) ON COMMIT DROP;

INSERT INTO _ivan_leandro_completo_expected (
  slug,
  expected_rows,
  expected_lme_rows,
  old_coverage_id,
  coverage_id,
  coverage_scope
)
VALUES
    ('ivan-moraes', 50, 0, 'ivan-moraes-recife-openlegis-autoria-principal-ampliado-parcial-20260507', 'ivan-moraes-recife-openlegis-completo-autoria-principal-pl-pelo-2017-2024-cutoff-20260512', 'inventario_completo_recife_openlegis_autoria_principal_pl_pelo_2017_2024_cutoff_20260512'),
    ('leandro-grass', 78, 0, 'legislacao-unblock-19-projetos-lei-lote-b-20260508', 'leandro-grass-cldf-ple-completo-autoria-principal-pl-2019-2022-cutoff-20260512', 'inventario_completo_cldf_ple_autoria_principal_pl_2019_2022_cutoff_20260512');

DO $$
DECLARE
  expected record;
  cand_id uuid;
  seed_count int;
  existing_accepted_count int;
  blocked_conflict_count int;
  target_count int;
  metadata_count int;
  old_count int;
  lme_count int;
  other_slug_count int;
BEGIN
  FOR expected IN SELECT * FROM _ivan_leandro_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = expected.slug AND publicavel = true;

    IF cand_id IS NULL THEN
      RAISE NOTICE '%: candidato publico ausente neste banco local/CI minimo; promocao completa escopada pulada', expected.slug;
      CONTINUE;
    END IF;

    SELECT count(*) INTO seed_count
    FROM _ivan_leandro_completo_seed
    WHERE slug = expected.slug;

    IF seed_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: seed tem % rows, esperado %', expected.slug, seed_count, expected.expected_rows;
    END IF;

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    IF lme_count <> expected.expected_lme_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: LME mudou de % para %', expected.slug, expected.expected_lme_rows, lme_count;
    END IF;

    SELECT count(*) INTO existing_accepted_count
    FROM projetos_lei pl
    JOIN _ivan_leandro_completo_seed seed
      ON seed.slug = expected.slug
     AND seed.proposicao_id_api = pl.proposicao_id_api
    WHERE pl.candidato_id = cand_id
      AND pl.coverage_id IN (expected.old_coverage_id, expected.coverage_id);

    IF existing_accepted_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pre-condicao %: promocao exige % rows ja existentes com coverage parcial antigo ou completo alvo; encontrou %', expected.slug, expected.expected_rows, existing_accepted_count;
    END IF;

    SELECT count(*) INTO blocked_conflict_count
    FROM projetos_lei pl
    JOIN _ivan_leandro_completo_seed seed
      ON seed.slug = expected.slug
     AND seed.proposicao_id_api = pl.proposicao_id_api
    WHERE pl.candidato_id = cand_id
      AND pl.coverage_id NOT IN (expected.old_coverage_id, expected.coverage_id);

    IF blocked_conflict_count <> 0 THEN
      RAISE EXCEPTION 'Pre-condicao %: % rows aceitas tem coverage_id conflitante', expected.slug, blocked_conflict_count;
    END IF;
  END LOOP;

  UPDATE projetos_lei pl
  SET
    tipo = seed.tipo,
    numero = seed.numero,
    ano = seed.ano,
    ementa = seed.ementa,
    fonte = seed.fonte,
    url_inteiro_teor = seed.url_inteiro_teor,
    coverage_id = seed.coverage_id,
    coverage_scope = seed.coverage_scope,
    metadata = COALESCE(pl.metadata, '{}'::jsonb) || seed.metadata
  FROM _ivan_leandro_completo_seed seed
  JOIN candidatos c ON c.slug = seed.slug AND c.publicavel = true
  WHERE pl.candidato_id = c.id
    AND pl.proposicao_id_api = seed.proposicao_id_api
    AND pl.coverage_id IN (seed.metadata->>'previous_coverage_id', seed.coverage_id);

  FOR expected IN SELECT * FROM _ivan_leandro_completo_expected LOOP
    SELECT id INTO cand_id FROM candidatos WHERE slug = expected.slug AND publicavel = true;

    IF cand_id IS NULL THEN
      CONTINUE;
    END IF;

    SELECT count(*) INTO target_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.coverage_id
      AND coverage_scope = expected.coverage_scope;

    SELECT count(*) INTO metadata_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.coverage_id
      AND coverage_scope = expected.coverage_scope
      AND metadata->>'coverage_status' = 'completo_escopado'
      AND metadata->>'coverage_public_status' = 'parlamentar_complete'
      AND metadata->>'tabela_alvo' = 'projetos_lei'
      AND metadata->>'legislacao_mandato_executivo_mixed' = 'false'
      AND metadata->>'autoria_principal_verificada' = 'true';

    SELECT count(*) INTO old_count
    FROM projetos_lei
    WHERE candidato_id = cand_id
      AND coverage_id = expected.old_coverage_id;

    SELECT count(*) INTO lme_count
    FROM legislacao_mandato_executivo
    WHERE candidato_id = cand_id;

    SELECT count(*) INTO other_slug_count
    FROM projetos_lei
    WHERE candidato_id <> cand_id
      AND coverage_id = expected.coverage_id;

    IF target_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows completas, esperado %', expected.slug, target_count, expected.expected_rows;
    END IF;

    IF metadata_count <> expected.expected_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows com metadata completa, esperado %', expected.slug, metadata_count, expected.expected_rows;
    END IF;

    IF old_count <> 0 THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows ainda no coverage parcial antigo', expected.slug, old_count;
    END IF;

    IF lme_count <> expected.expected_lme_rows THEN
      RAISE EXCEPTION 'Pos-condicao %: LME mudou de % para %', expected.slug, expected.expected_lme_rows, lme_count;
    END IF;

    IF other_slug_count <> 0 THEN
      RAISE EXCEPTION 'Pos-condicao %: % rows de outros slugs com coverage_id alvo', expected.slug, other_slug_count;
    END IF;
  END LOOP;
END $$;
